    public function index()
    {
        $cities  = City::latest()->get();
        $themes = Theme::where('user_id',43)->where(function($query) {
                    $query->where('theme_type','birthday')
                            ->orWhere('theme_type','marriage','pawteam');
                })->get();
           
        /*
            $states = State::where(function($query) { 
                })->get();
        */
        
        $states =  CustomerState::where('state_status',1) 
        ->orderBy('state_name','asc')->get();

        $pawteam = User::where('new_paw_team',1)->get();
                
        $pawteam1  = User::select('id','name','role_id','is_active','is_paw_team') 
                        ->where('users.role_id',"!=",4)
                        ->where('users.is_active',1) 
                        ->where('users.is_paw_team',1) 
                        ->where('users.new_paw_team',1) 
                        ->orderBy('users.name','Asc')
                        ->get();


        return view('admin.custom_leads',compact(['cities','themes','states','pawteam']));
    }

