                $historyItems = array_filter(explode('|', $lead->resubmission_history));
                
                foreach ($historyItems as $index => $item) {
                    $isSubmission = false;
                    if (in_array($lead->lead_status, ['Pending', 'Approved'])) {
                        $isSubmission = ($index % 2 == 0);
                    } else {
                        $isSubmission = ($index % 2 != 0);
                    }
                    if ($isSubmission) {
                        $label = '<span style="color:#11998e; font-weight:600;">Submitted on</span>';
                    } else {
                        $label = '<span style="color:#e53e3e; font-weight:600;">Rejected on</span>';
                    }
                    $historyHtml .= '<div style="margin-bottom:12px; padding-bottom:12px; border-bottom:1px dashed #e2e8f0;">';
                    $historyHtml .= '<div style="color:#4a5568; font-size:14px;"><strong>' . ($index + 1) . ')</strong> <i class="fas fa-calendar-alt" style="margin-left:4px; margin-right:8px; color:#863ac1;"></i> ' . $label . ' - <strong>' . trim($item) . '</strong></div>';
                    $historyHtml .= '</div>';
                }
                
                if (!empty($lead->first_posted_date)) {
                    $historyHtml .= '<div style="margin-top:16px; padding:12px; background:#f8f9fa; border-radius:6px; border-left:4px solid #863ac1;">';
                    $historyHtml .= '<div style="color:#2d3748; font-size:14px;"><i class="fas fa-flag-checkered" style="margin-right:8px; color:#863ac1;"></i> Submitted on - <strong>' . date('d M Y, h:i A', strtotime($lead->first_posted_date)) . '</strong></div>';
                    $historyHtml .= '</div>';
                }
                
                $historyHtml .= '</div>';
                
                $jsonHtml = htmlspecialchars(json_encode($historyHtml), ENT_QUOTES, 'UTF-8');
                
                $typerow .= '<div style="margin-top:12px; text-align:center;" id="history-popup-container-' . $lead->id . '">';
                $typerow .= '<i class="fas fa-info-circle" style="color:#863ac1; font-size:24px; cursor:pointer; filter:drop-shadow(0 2px 4px rgba(134,58,193,0.4)); transition:transform 0.2s;" onmouseover="this.style.transform=\'scale(1.1)\'" onmouseout="this.style.transform=\'scale(1)\'" onclick="Swal.fire({title: \'Lead History\', html: ' . $jsonHtml . ', confirmButtonColor: \'#863ac1\', showCloseButton: true, width: \'500px\'})"></i>';
                $typerow .= '</div>';
            }
           return $typerow;
           
        })
