     public function getdata1kavitha(Request $request)
    {
        $cityname = $request->input('cityname');
        
         $selectteamid = $request->input('selectteamid'); 
        
        $leads = 
        CustombuyLead::select([
            'id', 'customer_name', 'customer_email', 'customer_mobile', 'city', 'buy_leads_description', 'buyleads_city', 'buyleads_type', 'meeting_leadtype', 'meetingaddress', 'buyleads_price','created_at','updated_at','leadremarks','followup','follow_done','connected_by','lead_status','weddinglist_items',
            'followup_count', 'first_follow_up','second_follow_up','third_follow_up','fourth_follow_up','fifth_follow_up','sixth_follow_up','seventh_follow_up','last_follow_up',
            
            'checkchatcount','checkclientcount','checkconsultationcount','checkcuspaylatercount','checkcustombuyleadcount','checkgeneralleadcount',
            'checkhoneymoonformcount','checkleadformcount','checkmetaversecount',
            'checkotherleadcount','checkpaylatercount','checkquotationcount','checkusercount','checkwppckagescount','lead_moved_from','admin_approval','first_posted_date','resubmission_history',
            
            DB::raw("CONCAT('<b>Customer Name :</b> ',custom_buyleads.customer_name,'<br>','<b>Customer Email :</b> ',custom_buyleads.customer_email,'<br>','<b>Customer Mobile :</b> ',custom_buyleads.customer_mobile,'<br>','<b>Customer City :</b> ',custom_buyleads.city,'<br>','<b>Created Date :</b> ',custom_buyleads.created_at) as cusleaddetails"),
            DB::raw("CONCAT(custom_buyleads.weddinglist_items) as cusdetails"),
        ])->where('move_toleads','0')->where('connected_by',"=", "7140")->orderByRaw('COALESCE(last_resubmitted_at, created_at) DESC');
        
