        $selectteamid = $request->input('selectteamid'); 
        
        $leads = 
        CustombuyLead::select([
           'id', 'customer_name', 'customer_email', 'customer_mobile', 'city', 'buy_leads_description', 'buyleads_city', 'buyleads_type', 'meeting_leadtype', 'meetingaddress', 'buyleads_price','created_at','updated_at','leadremarks','followup','follow_done','connected_by','lead_status','weddinglist_items',
            'followup_count', 'first_follow_up','second_follow_up','third_follow_up','fourth_follow_up','fifth_follow_up','sixth_follow_up','seventh_follow_up','last_follow_up',
            
            'checkchatcount','checkclientcount','checkconsultationcount','checkcuspaylatercount','checkcustombuyleadcount','checkgeneralleadcount',
