    public function getdata1suji(Request $request)
    {
        $cityname = $request->input('cityname');
        
         $selectteamid = $request->input('selectteamid'); 
        
        $leads = 
        CustombuyLead::select([
            'id', 'customer_name', 'customer_email', 'customer_mobile', 'city', 'buy_leads_description', 'buyleads_city', 'buyleads_type', 'meeting_leadtype', 'meetingaddress', 'buyleads_price','created_at','updated_at','leadremarks','followup','follow_done','connected_by','lead_status','weddinglist_items',
            'followup_count', 'first_follow_up','second_follow_up','third_follow_up','fourth_follow_up','fifth_follow_up','sixth_follow_up','seventh_follow_up','last_follow_up',
            
            'checkchatcount','checkclientcount','checkconsultationcount','checkcuspaylatercount','checkcustombuyleadcount','checkgeneralleadcount',
            'checkhoneymoonformcount','checkleadformcount','checkmetaversecount',
            'checkotherleadcount','checkpaylatercount','checkquotationcount','checkusercount','checkwppckagescount','lead_moved_from','admin_approval','first_posted_date','resubmission_history',
            
            DB::raw("CONCAT('<b>Customer Name :</b> ',custom_buyleads.customer_name,'<br>','<b>Customer Email :</b> ',custom_buyleads.customer_email,'<br>','<b>Customer Mobile :</b> ',custom_buyleads.customer_mobile,'<br>','<b>Customer City :</b> ',custom_buyleads.city,'<br>','<b>Created Date :</b> ',custom_buyleads.created_at) as cusleaddetails"),
            DB::raw("CONCAT(custom_buyleads.weddinglist_items) as cusdetails"),
        ])->where('move_toleads','0')->where('connected_by',"=", "20125")->orderByRaw('COALESCE(last_resubmitted_at, created_at) DESC');
        
        if(!empty($cityname))
        {
            $leads = $leads->where('custom_buyleads.city','like', "%$cityname%");
        }

        if(!empty($selectteamid))
        { 
            $leads = $leads->where('connected_by',$selectteamid);
        }
        
        return Datatables::of($leads)
        ->addIndexColumn()
        ->addColumn('cusdetails', function($lead){
           // return $lead->cusdetails;
           
                $typerow ='';

                if(!empty($lead->weddinglist_items))
                {
                    $typerow .=' <p>'.$lead->weddinglist_items .'';
                
                }
             
             
                 $typerow .='
                    <div class="additoinal_bg"><p>Follow Up Counts </p></div>
                ';
                
                    if($lead->followup_count == "1")
                    {
                         $typerow .= '<select name="is_type" class="goaltype lesswid" id="typefollowid'.$lead->id.'">
                            <option value="">--Select---</option>
                            <option value="1" selected>1</option>
                            <option value="2">2</option>
                            <option value="3">3</option>
                            <option value="4">4</option> 
                            <option value="5">5</option> 
                            <option value="6">6</option> 
                            <option value="7">7</option> 
                            <option value="8">8</option> 
                         </select><br>
                        <button type="submit" class="btn btn-primary btn-sm add_type_details butwidth" name="add_type_details" onclick="event.preventDefault();setfollowtype(\''.$lead->id.'\');">ok</button>
                         <p class="doneshowfollow" id="this-'.$lead->id.'"><p>';
                    }
                    else if($lead->followup_count == "2")
                    {
                         $typerow .= '<select name="is_type" class="goaltype lesswid" id="typefollowid'.$lead->id.'">
                            <option value="">--Select---</option>
                            <option value="1">1</option>
                            <option value="2" selected>2</option>
                            <option value="3">3</option>
                            <option value="4">4</option> 
                            <option value="5">5</option> 
                            <option value="6">6</option> 
                            <option value="7">7</option> 
                            <option value="8">8</option> 
                         </select><br>
                        <button type="submit" class="btn btn-primary btn-sm add_type_details butwidth" name="add_type_details" onclick="event.preventDefault();setfollowtype(\''.$lead->id.'\');">ok</button>
                         <p class="doneshowfollow" id="this-'.$lead->id.'"><p>';
                    }
                    else if($lead->followup_count == "3")
                    {
                         $typerow .= '<select name="is_type" class="goaltype lesswid" id="typefollowid'.$lead->id.'">
                            <option value="">--Select---</option>
                            <option value="1">1</option>
                            <option value="2">2</option>
                            <option value="3" selected>3</option>
                            <option value="4">4</option> 
                            <option value="5">5</option> 
                            <option value="6">6</option> 
                            <option value="7">7</option> 
                            <option value="8">8</option> 
                         </select><br>
                        <button type="submit" class="btn btn-primary btn-sm add_type_details butwidth" name="add_type_details" onclick="event.preventDefault();setfollowtype(\''.$lead->id.'\');">ok</button>
                         <p class="doneshowfollow" id="this-'.$lead->id.'"><p>';
                    }
