                        </div>
                    </div>
            
            '
            )
      
        ->addColumn('checkbox', '<input type="checkbox" name="leads_checkbox[]" class="leads_checkbox" value="{{$id}}" disabled/>')
        
         
        
        
        ->rawColumns(['checkbox','action','remarksrow','cusdetails','statusrow','typerow','explainrow','cusleaddetails','pricerow'])
         
        
         ->filterColumn('cusdetails', function($query, $keyword) {
            $sql = "CONCAT(custom_buyleads.customer_name,'<br>','Email : ',custom_buyleads.customer_email,'<br>','Mobile : ',custom_buyleads.customer_mobile,
            '<br>',custom_buyleads.city)  like ?";
            $query->whereRaw($sql, ["%{$keyword}%"]);
        })
        
        ->make(true);
    }


