            $typerow .= '<option value="Pending" '.($lead->lead_status == "Pending" ? "selected" : "").'>Pending</option>';
            $typerow .= '<option value="Approved" '.($lead->lead_status == "Approved" ? "selected" : "").'>Approved</option>';
            $typerow .= '<option value="Rejected" '.($lead->lead_status == "Rejected" ? "selected" : "").'>Rejected</option>';
            $typerow .= '</select>';
