    public function store(Request $request)
    {
        //dd($request->event_category);
        
        if($request->item_lead_type == "meeting")
        {
            if($request->event_category_meeting == 'In Person Meeting')
            {
                $rules = array(
                    'name' => 'required',
                    'email'  => 'required',
                    'mobile' => 'required',
                    'executive_name'  => 'required',
                    'package_type_meeting' => 'required',
                    'lead_type' => 'required',
                    'meeting_time' => 'required',
                    'status' => 'required',
                    'city' => 'required',
                    'expiry_date' => 'required',
                    //'purchase_allowed' => 'required',
                    'event_category_meeting' => 'required',
                    'event_location' => 'required',
                    'address' => 'required',
                );
            }
            else
            {
                $rules = array(
                    'name' => 'required',
                    'email'  => 'required',
                    'mobile' => 'required',
                    'executive_name'  => 'required',
                    'package_type_meeting' => 'required',
                    'lead_type' => 'required',
                    'meeting_time' => 'required',
                    'status' => 'required',
                    'city' => 'required',
                    'expiry_date' => 'required',
                    //'purchase_allowed' => 'required',
                    'event_category_meeting' => 'required',
                    'event_location' => 'required',
                    //'address' => 'required',
                );
            }
        }
        else
        {
            $rules = array(
                'name' => 'required',
                'email'  => 'required',
                'mobile' => 'required',
                'executive_name'  => 'required',
                'package_type' => 'required',
                'lead_type' => 'required',
                'lead_time' => 'required',
                'status' => 'required',
                'city' => 'required',
                'expiry_date' => 'required',
                //'purchase_allowed' => 'required',
                'event_category' => 'required',
                'event_location' => 'required',
            );
        }
        
        $error = Validator::make($request->all(), $rules);

        if($error->fails())
        {
            return response()->json(['errors' => $error->errors()->all()]);
        }
        
        $path = '';
        if ($request->hasFile('lead_audio'))
        {
            $path = $request->file('lead_audio')->store('leadaudios');
        }
        
        if(!empty($request->address))
        {
            $address = $request->address;
        }
        else
        {
            $address = '';
        }
        
        if($request->item_lead_type == "meeting")
        {
            $package_type = $request->package_type_meeting;
            $event_categories =  $request->event_category_meeting;
            
            $lead_time =  $request->meeting_time;
            
            if(!empty($request->event_dates))
            {
                $event_date = $request->event_dates;
            }
            else
            {
                $event_date = '';
            }
        }
        else
        {
            $package_type = $request->package_type;
            $event_categories =  $request->event_category;
            $lead_time =  $request->lead_time;
            
            if(!empty($request->event_date))
            {
                $event_date = $request->event_date;
            }
            else
            {
                $event_date = '';
            }
        }
        
        
        $customer = new Customer();
                
        $customer->name = $request->name;
        $customer->email = $request->email;
        $customer->mobile = $request->mobile;
        $customer->lead_source = "Buy Lead";
          
          if($customer->save())
            {      
                $lead = new GeneralLead();
                
                $lead->name  =  $request->name;
                $lead->email    =  $request->email;
                $lead->mobile   =  $request->mobile;
                $lead->executive_name  = $request->executive_name;
                $lead->package_type =  $package_type;
                $lead->lead_type =  $request->lead_type;
                $lead->lead_audio =  $path;
                
                $lead->event_date =  $event_date;
                $lead->lead_time =  $lead_time;
                $lead->status =  $request->status;
                $lead->city =  $request->city;
                $lead->lead_description =  $request->lead_description;
                $lead->expiry_date =  $request->expiry_date;
                
                $lead->wedding_type =  $request->wedding_type;
                
                $lead->purchase_allowed =  $request->purchase_allowed;
                
                $lead->price =  $this->leadprice($request->lead_type);
                
                //$event_categories =  $request->event_category;
                
                $lead->address =  $address;
                

                /*
                $event_category = "";
                
                foreach($event_categories as $cat)
                {
                    $event_category .= $cat.",";
                }
                
                $event_category = substr($event_category, 0, -1);
                
                $lead->event_category =  $event_category;
                */ 

                if(!empty($event_category))
                {
                    $lead->event_category =  $event_category;
                }
                else 
                {
                    $lead->event_category =  "wedding";
                }


                $lead->event_location =  $request->event_location;
                
                $lead->wedding_type =  $request->wedding_type;
                
                if($lead->save())
                {
                    $customer = new Customer();
                        
                    $customer->name = $request->name;
                    $customer->email = $request->email;
                    $customer->mobile = $request->mobile;
                    $customer->lead_source = "website";
                    
                    $this->maildatas($lead->id);
                    return response()->json(['success' => 'Data Added successfully.']);
                  
                }
                else
                {
                    return response()->json(['success' => 'Error in allotment. Please contact website admin.']);
                }
            }
            
            else
            {
                return response()->json([
                    'message' => 'customer not saved',
                ]);
            }
    }

