    public function massremove(Request $request)
    {
        $paylater_id_array = $request->input('id');
        $paylaters = CustombuyLead::whereIn('id', $paylater_id_array)->get();
        
        //dd($paylaters);

        foreach($paylaters as $item)
        {
            /*
            if(Storage::disk('public')->exists($item->file))
            {
                Storage::delete($item->file);
            }
            */
            $data = CustombuyLead::where('id', $item->id)->first();
            
            $data->delete();
        }
        
        echo 'Data Deleted';
    }
    
    private function leadprice($leadtype)
    {
        if(is_numeric($leadtype))
        {
            return $leadtype;
        }
        else if($leadtype == 'No deduction')
        {
            return 0;
        }
        else if($leadtype == 'warming up')
        {
            return 50;
        }
        else if($leadtype == 'active')
        {
            return 100;
        }
        else if($leadtype == 'super active')
        {
            return 150;
        }
        else if($leadtype == 'Premium')
        {
            return 200;
        }
        else if($leadtype == 'hot')
        {
            return 250;
        }
        else if($leadtype == 'Ultra Premium')
        {
            return 500;
        }
        else if($leadtype == 'Overwhelming')
        {
            return 1000;
        }
        else if($leadtype == 'platinum')
        {
            return 350;
        }
        else if($leadtype == 'diamond')
        {
            return 750;
        }
        else 
        {
            return "Free";
        }   
    }
