    private function maildatas($id)
    {
        $lead = GeneralLead::findOrFail($id);
        $package_type = $lead->package_type;
        $event_category = $lead->event_category;
        $city = $lead->city;
        
        $data_cus = array('cus_name'=>$lead->name, 'cus_email' => $lead->email, 'cus_mobile' => $lead->mobile, 'cus_city' => $lead->city, 'cus_category' => $lead->event_category, 
        'cus_evedate' => $lead->event_date, 'cus_packtype' => $lead->package_type);
        
        //dd($lead->email);
        
           $mailstatus = Mail::to($lead->email)->send(new CustomerLeadMail($data_cus));
        

           $mailstatus1 = Mail::to(['enquiry@planawedding.in'])->send(new CustomerLeadMail($data_cus));

        /*
            $users = User::select('id','name','email','mobile','username','business_name','toss_actual_pass')->where('role_id',4)->where('is_active',1)->where('specialization','like', "%$package_type,%")->orWhere('specialization','like', "%,$package_type,%")
                ->orWhere('specialization','like', "%,$package_type")->orWhere('specialization','like', "$package_type")->get()->toArray();
        */
        
        $removeusers = GeneralLeadBuy::where('general_leads_id',$lead->id)->pluck('user_id');
        
        if($event_category == "In Person Meeting" || $event_category == "1.29 lakh wedding package" || $event_category == "1.69 lakh wedding package" || $event_category == "Connect over call" || $event_category == "Office Location" || $event_category == "Virtual Meeting" || $event_category == "Client Place")
        {
            $users = User::select('id','name','email','mobile','username','business_name','toss_actual_pass','city','android_token','iphone_token')
            ->where('role_id',4)
            ->where('is_active',1)
            ->where('show_in_mapep',1)
            ->where('city','like', "%$city%")
            ->where(function($query) use ($package_type){
                        $query->where('specialization','like', "%$package_type,%")
                                ->orWhere('specialization','like', "%,$package_type,%")
                                ->orWhere('specialization','like', "%,$package_type")
                                ->orWhere('specialization','like', "$package_type");
                    })
                    ->whereNotIn('id',$removeusers)
                    ->get()->toArray();
        }
        else
        {
            $users = User::select('id','name','email','mobile','username','business_name','toss_actual_pass','city','android_token','iphone_token')
            ->where('role_id',4)
            ->where('is_active',1)
            ->where('city','like', "%$city%")
                    ->where(function($query) use ($package_type){
                                $query->where('specialization','like', "%$package_type,%")
                                        ->orWhere('specialization','like', "%,$package_type,%")
                                        ->orWhere('specialization','like', "%,$package_type")
                                        ->orWhere('specialization','like', "$package_type");
                            })
                            ->whereNotIn('id',$removeusers)
                            ->get()->toArray();
        }

        $arraycount = count(array_chunk($users,100));  
        $array_chunk = array_chunk($users,100);
        
        for($i = 0;$i < $arraycount;$i++)
        {
            $usersmobile = "";
            $users = $array_chunk[$i];
            $counter = 0;
            
            foreach($users as $user)
            {
                $counter++;
                $usersmobile .= $user['mobile'].","; 
                $notification = new Notification();
                
                $notification->user_id = $user['id'];
                $notification->lead_id = $lead->id;
                $notification->lead_type = "general_leads";
                $notification->lead_package = $lead->package_type;

                $notification->save();
                
