    private function saveBuyLeadLog_1($lead_id, $custom_lead_id, $lead_name, $package_type, $sent_for, $message)
        {
            \App\BuyleadNotificationsLog::create([
                'lead_id'        => $lead_id,
                'custom_lead_id' => $custom_lead_id,
                'lead_name'      => $lead_name,
                'package_type'   => $package_type,
                'sent_for'       => $sent_for,
                'type'           => "BUY LEAD",
                'message'        => $message,
            ]);
        }

    public function saveBuyLeadLog($lead_id, $custom_lead_id, $lead_name, $package_type, $sent_for, $message)
        {
            // ---------------------------------------
            // SAVE LOG ENTRY
            // ---------------------------------------
            $log = new \App\BuyleadNotificationsLog();
            $log->lead_id        = $lead_id;
            $log->custom_lead_id = $custom_lead_id;
            $log->lead_name      = $lead_name;
            $log->package_type   = $package_type;
            $log->sent_for       = $sent_for;
            $log->message        = $message;
            $log->save();

            // ---------------------------------------
            // GET ALL USERS WHO SHOULD RECEIVE THIS
            // ---------------------------------------
            $users = User::where('is_active', 1)
                        ->where(function($q) use($sent_for){
                            $q->where('specialization', 'LIKE', "%$sent_for%");
                        })
                        ->get();

            // ---------------------------------------
            // INSERT UNREAD STATUS FOR EACH USER
            // (tinyint → 0 = unread | 1 = read)
            // ---------------------------------------
            foreach ($users as $u) {
                \DB::table('buylead_notification_user_status')->insert([
                    'log_id'     => $log->id,
                    'user_id'    => $u->id,
                    'is_read'    => 0,  // unread
                    'created_at' => now(),
                    'updated_at' => now(),
                ]);
            }
        }


    

