    public function movedatas_faster_but_not_sending($id)
        {
                    // Helper function to send batch notifications efficiently
                    $sendBatchNotifications = function($eventplanners, $title, $message, $access_token) {
                    if(!$eventplanners || count($eventplanners) == 0) {
                    return;
                    }

                    $projectId= "wedding-planner-2ffbe";
                    $url = "https://fcm.googleapis.com/v1/projects/{$projectId}/messages:send";

                    $headers =array(
                    "Authorization: Bearer $access_token",
                    "content-type: application/json"
                    );

                    // Batch processing with cURL multi-handle for better performance
                    $batchSize = 50; // Process 50 notifications at a time
                    $batches = array_chunk($eventplanners->toArray(), $batchSize);

                    foreach($batches as $batch)
                    {
                    $multiHandle = curl_multi_init();
                    $curlHandles = [];

                    foreach($batch as $user)
                    {
                    // Fetch the full user row
                    $fullUser = User::find($user['user_id']);

                    // Default type
                    $type = "BUY LEADS";

                    // RULE APPLIED: if no subscription & not partner
                    if ($fullUser && $fullUser->chk_subscription == 0 && $fullUser->is_partner == 0) {
                    $type = "";
                    }

                    $postdata = [
                    "message" => [
                    "token" => $user['fcm_token'],
                    "notification" => [
                    "title" => $title,
                    "body" => $message,
                    "sound" => "joyful.caf", // Sound in notification section
                    ],
                    "data" => [
                    "title" => $title,
                    "body" => $message,
                    "type" => $type,
                    "click_action" => "FLUTTER_NOTIFICATION_CLICK",
                    ],
                    "android" => [
                    "notification" => [
                    "sound" => "joyful" // Android sound without extension
                    ]
                    ],
                    "apns" => [
                    "payload" => [
                    "aps" => [
                    "sound" => "joyful.caf" // iOS sound with extension
                    ]
                    ]
                    ]
                    ]
                    ];

                    $payload = json_encode($postdata);

                    $ch = curl_init();
                    curl_setopt($ch, CURLOPT_URL, $url);
                    curl_setopt($ch, CURLOPT_RETURNTRANSFER, 1);
                    curl_setopt($ch, CURLOPT_CONNECTTIMEOUT, 10);
                    curl_setopt($ch, CURLOPT_TIMEOUT, 30);
                    curl_setopt($ch, CURLOPT_CUSTOMREQUEST, "POST");
                    curl_setopt($ch, CURLOPT_POSTFIELDS, $payload);
                    curl_setopt($ch, CURLOPT_HTTPHEADER, $headers);

                    curl_multi_add_handle($multiHandle, $ch);
                    $curlHandles[] = $ch;
                    }

                    // Execute all requests simultaneously
                    $running = null;
                    do {
                    curl_multi_exec($multiHandle, $running);
                    curl_multi_select($multiHandle);
                    } while ($running > 0);

                    // Close all handles
                    foreach($curlHandles as $ch) {
                    curl_multi_remove_handle($multiHandle, $ch);
                    curl_close($ch);
