    public function reset($id)
    {
        $lead = GeneralLead::findOrFail($id);
        
        if($lead)
        {
            $lead->status = 'not-purchased';
            $lead->user_id = NULL;
            $lead->payment_initiated = '0';
            
            if($lead->save())
            {
                $resultString['status'] = 1;
                echo(json_encode($resultString));
            }
            else
            {
                $resultString['status'] = 2;
                echo(json_encode($resultString));
            }
        }
        else
        {
            $resultString['status'] = 2;
            echo(json_encode($resultString));
        }
    }
    
