    public function leadfollowup(Request $request) 
    {
        $id = $request->leadid;
        
         
        
        $custombuylead = CustombuyLead::where("id",$id)->latest()->first();
        
        if($custombuylead)
        {
            $custombuylead->followup = $request->followon; 
            
            
                
            if($custombuylead->save())
            { 
                $Followupss = Followup::where("custom_leads_id",$id)->get()->count();
                  
                if($Followupss>0)
                {
                    $Followups = Followup::where("custom_leads_id",$id)->latest()->first();
                    $Followups->followup = $request->followon; 
                    $Followups->save();
                }
                else
                {
                    $followup = new Followup();
                    $followup->name = $custombuylead->name;;
                    $followup->email =$custombuylead->email;
                    $followup->mobile = $custombuylead->mobile;
                    $followup->frompaw = 'Custom Lead Form - Assign Lead';
                    
                    $followup->custom_leads_id = $custombuylead->id;
                    $followup->conected_by = $custombuylead->connected_by;
                    $followup->followup = $request->followon;
                    
                    $followup->save();
                }
                
                return response()->json([
                    'message' => 'data saved',
                    'status' => '1',
                ]);
            }
            else
            {
                return response()->json([
                    'message' => 'data not saved',
                    'status' => '0',
                ]);
            }
        }
        else
        {
             return response()->json([
                    'message' => 'data not found',
                    'status' => '2',
                ]);
        }
    }
    
