           public function setleadstatus($id, $value)
    {
        $resultString = [];
        $data = CustombuyLead::findOrFail($id);
        
        $data->lead_status = $value;
        
        if ($value == 'Pending') $data->admin_approval = 'pending';
        if ($value == 'Rejected') {
            if ($data->admin_approval != 'rejected') {
                $history = $data->resubmission_history ? " | " . $data->resubmission_history : "";
                $data->resubmission_history = date("d M Y, h:i A") . $history;
            }
            $data->admin_approval = 'rejected';
        }

        if ($data->resubmission_history) {
            $historyHtml = '<div style="font-family:\'Inter\',sans-serif; text-align:left;">';
            $historyHtml .= '<div style="background:#f3e8ff; border-radius:8px; padding:15px; margin-bottom:20px; text-align:center; border:1px solid #d8b4fe;">';
            $historyHtml .= '<div style="font-size:18px; font-weight:700; color:#5b247a;">' . htmlspecialchars($data->customer_name) . '</div>';
            $historyHtml .= '<div style="font-size:14px; color:#6b7280; margin-top:5px;"><i class="fas fa-phone-alt" style="color:#863ac1; font-size:12px;"></i> ' . htmlspecialchars($data->customer_mobile) . ' &nbsp;|&nbsp; ID: #' . $data->id . '</div>';
            $historyHtml .= '</div>';
            
            $dates = explode(" | ", $data->resubmission_history);
            $count = count($dates);
            foreach ($dates as $index => $date) {
                $isSubmission = false;
                if (in_array($data->lead_status, ['Pending', 'Approved'])) {
                    $isSubmission = ($index % 2 == 0);
                } else {
                    $isSubmission = ($index % 2 != 0);
                }
                if ($isSubmission) {
                    $label = '<span style="color:#11998e; font-weight:bold;">Submitted on</span>';
                } else {
                    $label = '<span style="color:#ef473a; font-weight:bold;">Rejected on</span>';
                }
                $historyHtml .= '<div style="padding:10px 0; border-bottom:1px dashed #e5e7eb; font-size:14px; color:#374151;">';
                $historyHtml .= '<strong>' . ($index + 1) . ')</strong> <i class="fas fa-calendar-alt" style="color:#863ac1;"></i> ' . $label . ' - <strong>' . htmlspecialchars(trim($date)) . '</strong>';
                $historyHtml .= '</div>';
            }
            $historyHtml .= '<div style="padding:15px; background:#f9fafb; border-radius:8px; margin-top:15px; font-size:14px; color:#374151; border-left:4px solid #863ac1;">';
            $historyHtml .= '<i class="fas fa-flag-checkered" style="color:#863ac1;"></i> Submitted on - <strong>' . date('d M Y, h:i A', strtotime($data->created_at)) . '</strong>';
            $historyHtml .= '</div>';
            $historyHtml .= '</div>';
            
            $jsonHtml = json_encode($historyHtml);
            $resultString['popup_html'] = '<i class="fas fa-info-circle" style="color:#863ac1; font-size:24px; cursor:pointer; filter:drop-shadow(0 2px 4px rgba(134,58,193,0.4)); transition:transform 0.2s;" onmouseover="this.style.transform=\'scale(1.1)\'" onmouseout="this.style.transform=\'scale(1)\'" onclick="Swal.fire({title: \'Lead History\', html: ' . htmlspecialchars($jsonHtml, ENT_QUOTES, 'UTF-8') . ', confirmButtonColor: \'#863ac1\', showCloseButton: true, width: \'500px\'})"></i>';
        }
        
        if ($value == 'Approved' && $data->buyleads_type == 'Buy Lead') {
            $data->admin_approval = 'approved';
            $data->move_toleads = 1;
            $data->save();

            ob_start();
            $this->movedatas($id);
            ob_end_clean();

            $generalLead = \App\GeneralLead::where('custom_lead_id', $id)->orderBy('id', 'desc')->first();
            if ($generalLead) {
                $generalLead->lead_time = date('Y-m-d H:i:s');
                $generalLead->expiry_date = date('Y-m-d', strtotime('+7 days'));
                $generalLead->save();
            }
            
            $resultString['lastquoteid'] = "updated to $value and moved to general leads";
            echo(json_encode($resultString));
            return;
        }

        if($data->save())
        {
            $resultString['lastquoteid'] = "updated to $value";
            echo(json_encode($resultString));
        }
        else
        {
            $resultString['lastquoteid'] = '';
            echo(json_encode($resultString));
        }
    }

