    public function setfollowtype($id,$value)
        {
        $resultString = [];
        $data = CustombuyLead::findOrFail($id);
 
        $current_time = date("d/m/Y h:i:s");
        
        $data->followup_count = $value;
        
        if($value == "1")
        {
            $data->first_follow_up = $current_time;
        }
        else if($value == "2")
        {
            $data->second_follow_up = $current_time;
        }
        else if($value == "3")
        {
            $data->third_follow_up = $current_time;
        }
        else if($value == "4")
        {
            $data->fourth_follow_up = $current_time;
        }
        else if($value == "5")
        {
            $data->fifth_follow_up = $current_time;
        }
        else if($value == "6")
        {
            $data->sixth_follow_up = $current_time;
        }
        else if($value == "7")
        {
            $data->seventh_follow_up = $current_time;
        }
        else if($value == "8")
        {
            $data->last_follow_up = $current_time;
        }
        if($data->save())
        {
           /*if(empty($data->team_id))
            {
                $users = User::where('team_id',$data->id)->get();
                    
                foreach($users as $user)
