     public function setindiviteamdatas($teamid,$teamtype)
      {
          $teamid = $teamid;
           
            $teamtype = $teamtype;
           //dd($teamid);
           
           if(!empty($teamid) || ($teamid !="0"))
           {
               $leads = CustombuyLead::select([
                    'custom_buyleads.*',
                ])->where('custom_buyleads.move_toleads',0)->where('connected_by',$teamid)->where('custom_buyleads.lead_status',$teamtype)->count(); 
                
                
                $leadsall = CustombuyLead::select([
                    'custom_buyleads.*',
                ])->where('custom_buyleads.move_toleads',0)->where('connected_by',$teamid)->count(); 
                
                
                
           }
           else
           {
               $leads = CustombuyLead::select([
                    'custom_buyleads.*',
                ])->where('custom_buyleads.move_toleads',0)->where('custom_buyleads.lead_status',$teamtype)->count(); 
                
                $leadsall = CustombuyLead::select([
                    'custom_buyleads.*',
                ])->where('custom_buyleads.move_toleads',0)->count(); 
                 
           }
            if($leadsall)
            {
                 return response()->json([
                    'leads' => $leads,  
                    'leadsall' => $leadsall,  
                    'status' => '1',
                ]);
            }
            else
            {
                return response()->json([
                    'message' => "",
                    'status' => '0',
                ]);
            }
            
      }
      
      



      public function getstate($package_type)
    {
        
        $package_type = $package_type;


        if($package_type == "makeup-artists")
        {
            $packstype = "makeup";
        }
        else if($package_type == "photo&videographer")
        {
            $packstype = "photo";
        }
        else if($package_type == "flower-decorators")
        {
            $packstype = "decor";
        }
        else if($package_type == "mehendi artist")
        {
            $packstype = "mehendi";
        }
        else 
        {
            $packstype = $package_type;
        }
        
        $weddingpack = "wedding";

        $statesdata = CustomerState::join("users as b","b.user_lead_state_name","=","customer_states.state_name")
                /*->select(DB::raw("cities.*"),'count(appliedjobs.id) as counts', "b.name as business_name", "b.mobile as business_telephone", "b.city as business_city")   */
                ->select('customer_states.*', DB::raw('count(b.id) as counts'))
                //->where('cities.state_id', $stateid_arrays)  
                ->where('b.role_id', '4')
                ->where('b.specialization','like', '%'.$packstype.'%')
                ->orwhere('b.specialization','like', '%'.$weddingpack.'%')
                ->where('b.is_active', '1')
                ->groupBy('customer_states.state_name')
                ->get();
 
             
        $resultString = [];
        $resultString = ['status' => 1, 'message' => "Success",  'statesdata' => $statesdata];
        echo(json_encode($resultString));  
         
    }
      
}





